int integerBreak(int n) {
    int* dp = calloc(n + 1, sizeof(int)); dp[1] = 1;
    for (int i = 2; i <= n; i++)
        for (int j = 1; j < i; j++) {
            int v1 = dp[j] * (i - j), v2 = j * (i - j);
            int v = v1 > v2 ? v1 : v2;
            if (v > dp[i]) dp[i] = v;
        }
    int ans = dp[n]; free(dp); return ans;
}
